udt:



















.alert-filters {
    auto-size: grow fit;
    gap: 6;
    padding: 0 0 4 0;
}

.alert-filter-btn {
    padding: 4 12;
    font-size: 11;
    border-radius: 12;
    auto-size: fit;

    &:hover { background-color: 0x60FFFFFF; }
    &.active { stroke-color: 0x60FFD700; stroke-width: 1; stroke-inset: 1; stroke-radius: 10; }
}

.alert-feed {
    auto-size: grow;
    flow: vertical;
    gap: 4;
    overflow: scroll;
}

.alert-empty {
    auto-size: grow;
    flow: vertical;
    gap: 12;
    anchor: middle-center;
    padding: 40 0;
}
